import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';

const ProductDetailPage = () => {
  const { id } = useParams(); // Lấy ID từ đường dẫn
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const { data } = await axios.get(`http://localhost:5000/api/products/${id}`);
        setProduct(data);
      } catch (error) {
        console.error("Lỗi:", error);
      }
    };
    fetchProduct();
  }, [id]);

  if (!product) return <div className="text-center py-5">Đang tải...</div>;

  return (
    <div className="container py-4">
      {/* Nút quay lại */}
      <button className="btn btn-link text-decoration-none text-dark fw-bold mb-3" onClick={() => navigate('/')}>
        ⬅ Quay lại trang chủ
      </button>

      <div className="row">
        {/* CỘT TRÁI: ẢNH SẢN PHẨM */}
        <div className="col-md-8 mb-4">
          <div className="card border-0 shadow-sm p-2">
            <img 
              src={product.image} 
              alt={product.name} 
              className="w-100 rounded" 
              style={{maxHeight: '500px', objectFit: 'contain', backgroundColor: '#f0f0f0'}} 
            />
          </div>
          
          {/* MÔ TẢ CHI TIẾT */}
          <div className="card border-0 shadow-sm mt-3 p-4">
            <h5 className="fw-bold">Mô tả chi tiết</h5>
            <p style={{whiteSpace: 'pre-line'}}>{product.description}</p>
          </div>
        </div>

        {/* CỘT PHẢI: THÔNG TIN & LIÊN HỆ */}
        <div className="col-md-4">
          <div className="card border-0 shadow-sm p-3 mb-3">
            <h4 className="fw-bold mb-1">{product.name}</h4>
            <h3 className="text-danger fw-bold my-3">
              {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(product.price)}
            </h3>
            <p className="text-muted"><i className="bi bi-geo-alt-fill"></i> {product.location}</p>
            
            <hr />
            
            {/* THÔNG SỐ KỸ THUẬT (Dynamic) */}
            <div className="mb-3">
               {product.details && Object.entries(product.details).map(([key, value]) => (
                 <div className="d-flex justify-content-between mb-2" key={key}>
                    <span className="text-muted text-capitalize">{key}:</span>
                    <span className="fw-bold">{value}</span>
                 </div>
               ))}
            </div>
          </div>

          {/* BOX NGƯỜI BÁN */}
          <div className="card border-0 shadow-sm p-3">
             <div className="d-flex align-items-center mb-3">
                <div className="rounded-circle bg-warning d-flex align-items-center justify-content-center fw-bold" style={{width: '50px', height: '50px'}}>
                   AD
                </div>
                <div className="ms-3">
                   <h6 className="mb-0 fw-bold">Người Bán</h6>
                   <small className="text-muted">Hoạt động 5 phút trước</small>
                </div>
             </div>
             
             <button className="btn btn-success w-100 fw-bold py-2 mb-2 fs-5">
                📞 BẤM ĐỂ GỌI
             </button>
             <button className="btn btn-outline-success w-100 fw-bold py-2">
                💬 CHAT VỚI NGƯỜI BÁN
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetailPage;
